import { existsSync, readFileSync, writeFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

import prettier from 'prettier';

const scriptPath = fileURLToPath(import.meta.url);
export const projectRoot = resolve(dirname(scriptPath), '..');
export const CONTRACT_PATH = 'shared/contracts/whitelist-format.contract.json';

const GENERATED_BANNER =
  '@generated by scripts/generate-contract-constants.mjs from shared/contracts/whitelist-format.contract.json. Do not edit by hand - run `npm run contract:constants` at the OpenPath repo root.';

export function loadContract(rootDir = projectRoot) {
  const raw = JSON.parse(readFileSync(resolve(rootDir, CONTRACT_PATH), 'utf8'));
  const { disabledSentinel, sectionHeaders, captivePortalProbeDomains } = raw;
  if (!disabledSentinel.startsWith('#')) {
    throw new Error('disabledSentinel must start with "#"');
  }
  const { linux, windows, windowsDetectionHosts } = captivePortalProbeDomains;
  for (const domain of linux) {
    if (!windows.includes(domain)) {
      throw new Error(`linux probe domain ${domain} missing from windows probe list`);
    }
  }
  for (const domain of windowsDetectionHosts) {
    if (!windows.includes(domain)) {
      throw new Error(`windows detection host ${domain} missing from windows probe list`);
    }
  }
  return {
    disabledSentinel,
    disabledSentinelWord: disabledSentinel.replace(/^#\s*/, ''),
    sectionHeaders,
    linux,
    windows,
    windowsDetectionHosts,
  };
}

export async function buildTsConstants(contract) {
  const quoteList = (items) => items.map((item) => `  '${item}',`).join('\n');
  const source = `// ${GENERATED_BANNER}

/** First-line marker that disables enforcement for a whitelist.txt document. */
export const WHITELIST_DISABLED_SENTINEL = '${contract.disabledSentinel}';

/** Section headers of the whitelist.txt wire format, in canonical emit order. */
export const WHITELIST_SECTION_HEADERS = {
  whitelist: '${contract.sectionHeaders.whitelist}',
  blockedSubdomains: '${contract.sectionHeaders.blockedSubdomains}',
  blockedPaths: '${contract.sectionHeaders.blockedPaths}',
  allowedPaths: '${contract.sectionHeaders.allowedPaths}',
} as const;

/** Captive-portal probe domains the Linux agent must keep resolvable. */
export const LINUX_CAPTIVE_PORTAL_PROBE_DOMAINS = [
${quoteList(contract.linux)}
] as const;

/** Captive-portal probe domains the Windows agent must keep resolvable. */
export const WINDOWS_CAPTIVE_PORTAL_PROBE_DOMAINS = [
${quoteList(contract.windows)}
] as const;

/** Subset of probe domains Windows captive-portal recovery may open (W-3). */
export const WINDOWS_CAPTIVE_PORTAL_DETECTION_HOSTS = [
${quoteList(contract.windowsDetectionHosts)}
] as const;
`;
  const targetPath = resolve(projectRoot, 'shared/src/contract-constants.ts');
  const config = (await prettier.resolveConfig(targetPath)) ?? {};
  return prettier.format(source, { ...config, filepath: targetPath });
}

export function buildShConstants(contract) {
  return `#!/bin/bash
# ${GENERATED_BANNER}

# shellcheck disable=SC2034  # consumed by scripts that source this library
OPENPATH_CONTRACT_DISABLED_SENTINEL='${contract.disabledSentinel}'
# shellcheck disable=SC2034
OPENPATH_CONTRACT_DISABLED_SENTINEL_WORD='${contract.disabledSentinelWord}'
# shellcheck disable=SC2034
OPENPATH_CONTRACT_SECTION_WHITELIST='${contract.sectionHeaders.whitelist}'
# shellcheck disable=SC2034
OPENPATH_CONTRACT_SECTION_BLOCKED_SUBDOMAINS='${contract.sectionHeaders.blockedSubdomains}'
# shellcheck disable=SC2034
OPENPATH_CONTRACT_SECTION_BLOCKED_PATHS='${contract.sectionHeaders.blockedPaths}'
# shellcheck disable=SC2034
OPENPATH_CONTRACT_SECTION_ALLOWED_PATHS='${contract.sectionHeaders.allowedPaths}'

get_openpath_contract_captive_portal_probe_domains() {
    cat <<'EOF'
${contract.linux.join('\n')}
EOF
}
`;
}

// NOTE: Windows deliberately has NO generated include here. A concurrent session
// already extracted the Windows domain/detection-host lists into catalog functions
// (windows/lib/internal/Common.Domains.Catalog.ps1, windows/lib/CaptivePortal.psm1).
// A generated parallel PS1 function set would be dead duplication. Instead,
// windows/tests/Windows.ContractConstants.Tests.ps1 is a sync-guard that dot-sources
// those existing modules and asserts they still match this same contract.

export const GENERATED_TARGETS = [
  { path: 'shared/src/contract-constants.ts', build: buildTsConstants },
  { path: 'linux/lib/common-contract-constants.sh', build: buildShConstants },
];

export async function syncContractConstants(rootDir = projectRoot, { check = false } = {}) {
  const contract = loadContract(rootDir);
  const changed = [];

  for (const target of GENERATED_TARGETS) {
    const targetPath = resolve(rootDir, target.path);
    const nextContent = await target.build(contract);
    const currentContent = existsSync(targetPath) ? readFileSync(targetPath, 'utf8') : '';

    if (currentContent === nextContent) {
      continue;
    }

    changed.push(target.path);

    if (!check) {
      writeFileSync(targetPath, nextContent);
    }
  }

  return changed;
}

if (process.argv[1] && resolve(process.argv[1]) === scriptPath) {
  const changed = await syncContractConstants(projectRoot, {
    check: process.argv.includes('--check'),
  });

  if (changed.length === 0) {
    process.exit(0);
  }

  if (process.argv.includes('--check')) {
    console.error(`Contract constants are out of date: ${changed.join(', ')}`);
    process.exit(1);
  }

  console.log(`Updated contract constants: ${changed.join(', ')}`);
}
